/// <summary>
/// .NET 8 migration of the BackgroundProcessor.
///
/// Key changes from .NET Framework:
///   1. Thread.Abort() throws PlatformNotSupportedException in .NET 5+.
///      Replaced with CancellationToken cooperative cancellation.
///   2. ThreadAbortException can never be thrown — catch block removed.
///   3. Thread.ResetAbort() is gone — no equivalent needed with cooperative model.
///   4. Replaced raw Thread with Task.Run + async pattern for idiomatic .NET 8.
///   5. Stop() is now async and uses graceful timeout before forced cleanup.
/// </summary>
public class BackgroundProcessor : IDisposable
{
    private readonly CancellationTokenSource _cts = new();
    private Task? _workerTask;

    public void Start()
    {
        _workerTask = Task.Run(() => ProcessLoop(_cts.Token));
    }

    private async Task ProcessLoop(CancellationToken token)
    {
        while (!token.IsCancellationRequested)
        {
            try
            {
                // Pass the token so blocking calls can be interrupted cooperatively.
                var item = await GetNextItemAsync(token);
                await ProcessItemAsync(item, token);
            }
            catch (OperationCanceledException) when (token.IsCancellationRequested)
            {
                // Cancellation requested — roll back and exit cleanly.
                RollbackCurrentTransaction();
                break;
            }
            finally
            {
                FlushBuffers();
            }
        }
    }

    /// <summary>
    /// Gracefully stops the processor. Waits up to 2 seconds for the loop
    /// to finish its current item before giving up.
    /// </summary>
    public async Task StopAsync()
    {
        // Signal cancellation (replaces _running = false AND Thread.Abort)
        _cts.Cancel();

        if (_workerTask is not null)
        {
            // Wait up to 2 seconds for graceful shutdown
            using var timeoutCts = new CancellationTokenSource(TimeSpan.FromSeconds(2));
            try
            {
                await _workerTask.WaitAsync(timeoutCts.Token);
            }
            catch (TimeoutException)
            {
                // Worker didn't finish in time — it will still see the
                // cancelled token on its next iteration or await point.
                // Log a warning here in production code.
            }
            catch (OperationCanceledException)
            {
                // Expected — the worker noticed cancellation.
            }
        }
    }

    public void Dispose()
    {
        _cts.Cancel();
        _workerTask?.Wait(TimeSpan.FromSeconds(2));
        _cts.Dispose();
        GC.SuppressFinalize(this);
    }

